package com.trademaster.ims.mobile.orders.repository;import com.trademaster.ims.mobile.orders.model.CustomerReturnRequest;import com.trademaster.ims.mobile.orders.model.CustomerReturnRequestItem;import org.springframework.data.jpa.repository.*;import org.springframework.data.repository.query.Param;import java.util.*;public interface CustomerReturnRequestItemRepository extends JpaRepository<CustomerReturnRequestItem,Long>{List<CustomerReturnRequestItem>findByReturnRequestIdOrderByIdAsc(Long id);@Query("select coalesce(sum(i.requestedQuantity),0) from CustomerReturnRequestItem i join CustomerReturnRequest r on r.id=i.returnRequestId where i.orderItemId=:itemId and r.status in :statuses")Long activeRequestedQuantity(@Param("itemId")Long itemId,@Param("statuses")Collection<CustomerReturnRequest.Status>statuses);}
